// inferred-not-tested:原生 Testbed 全局挂 document,仅在隔离 iframe 内使用
import { World, Box, Circle, Testbed } from 'https://cdn.jsdelivr.net/npm/planck@1/with-testbed/+esm';
document.body.style.margin = '0'; document.body.style.height = '400px';
const world = new World({ gravity: data.gravity ?? { x: 0, y: -10 } });
for (const s of data.bodies) { const b = world.createBody({ type: s.type ?? 'static', position: s.position, angle: s.angle ?? 0 }); const shape = s.shape.kind === 'circle' ? new Circle(s.shape.radius ?? 1) : new Box(s.shape.halfWidth ?? 1, s.shape.halfHeight ?? 1); b.createFixture({ shape, density: s.density ?? (s.type === 'dynamic' ? 1 : 0), friction: s.friction ?? 0.2, restitution: s.restitution ?? 0 }); }
const testbed = Testbed.mount(); Object.assign(testbed, { x: 0, y: -10, width: 80, height: 60, ...(data.view ?? {}) });
testbed.start(world);
